---
import type { HTMLAttributes } from "astro/types";
import { cn } from "@/lib/utils";
import SemanticIcon from "../icon/SemanticIcon.astro";

interface Props extends HTMLAttributes<"div"> {
  value: string;
  disabled?: boolean;
  class?: string;
}

const {
  value,
  disabled = false,
  class: className = "",
  ...rest
} = Astro.props as Props;
---

<div
  {...rest}
  role="option"
  tabindex={disabled ? -1 : 0}
  data-slot="select-item"
  data-value={value}
  data-disabled={disabled ? "" : undefined}
  class={cn(
    "focus:bg-accent focus:text-accent-foreground not-data-[variant=destructive]:focus:**:text-accent-foreground gap-2 rounded-none py-2 pr-8 pl-2 text-xs [&_svg:not([class*='size-'])]:size-4 *:[span]:last:flex *:[span]:last:items-center *:[span]:last:gap-2",
    "group/item relative flex w-full cursor-default items-center outline-hidden select-none",
    "data-[disabled]:pointer-events-none data-[disabled]:opacity-50",
    "[&_svg]:pointer-events-none [&_svg]:shrink-0",
    className,
  )}
>
  <span
    data-slot="select-item-text"
    class="flex flex-1 gap-2 shrink-0 whitespace-nowrap"
    ><slot /></span
  >

  <span
    data-slot="select-item-indicator"
    class="pointer-events-none absolute right-2 flex size-4 items-center justify-center"
  >
    <span class="hidden items-center justify-center group-data-[selected]/item:inline-flex">
      <SemanticIcon name="check" class="size-4" />
    </span>
  </span>
</div>

